import React from 'react';
import { FiBell } from 'react-icons/fi';

const ALERTS = [
  { title: "New EU AI Act Update", time: "2h ago", type: "Urgent", desc: "Compliance requirements for LLM deployment have been updated." },
  { title: "Nvidia Blackwell Announcement", time: "1d ago", type: "Hardware", desc: "New architecture significantly reduces inference costs for your models." },
  { title: "Skill Trend: Agentic Workflows", time: "3d ago", type: "Rising", desc: "Demand for engineers who can build autonomous agents is up 45%." },
];

const TrendAlerts: React.FC = () => {
  return (
    <div className="space-y-4 animate-fadeIn">
      <h3 className="text-xl font-bold text-gray-900 mb-4 px-2">Industry Trends & Alerts</h3>
      {ALERTS.map((alert, i) => (
        <div key={i} className="bg-white p-5 rounded-2xl shadow-sm border border-gray-100 flex gap-4 group hover:border-blue-300 transition-colors">
          <div className="text-2xl text-blue-500 mt-1"><FiBell /></div>
          <div>
            <div className="flex items-center gap-2 mb-1">
              <span className="font-bold text-gray-900">{alert.title}</span>
              <span className="text-[10px] bg-gray-100 px-2 py-0.5 rounded text-gray-500">{alert.time}</span>
            </div>
            <p className="text-sm text-gray-500">{alert.desc}</p>
          </div>
        </div>
      ))}
    </div>
  );
};

export default TrendAlerts;
